(38, 'E2-0038AC', '', '', '', '', '', '', '', 'Treatment of values during the engineering educational process\nby Marino M. Mena ', '', 'Engineering educational processes', NULL, NULL, 'Public (Metadata Only)', 'active', '2026-03-18 08:36:49', '2026-03-18 08:36:49'),
(39, 'E2-0039AC', '', '', '', '', '', '', '', 'Environmental Undergraduate Research in Civil Engineering\nby Professor Marino M. Mena ', '', 'Environmental undergraduate research\nCivil engineering', NULL, NULL, 'Public (Metadata Only)', 'active', '2026-03-18 08:36:49', '2026-03-18 08:36:49'),
(40, 'E2-0040AC', '', '', '', '', '', '', '', 'Environmental and social concerns in highway transportation projects \nby Professor Marino M. Mena ', 'In recent years there has been increasing public awareness of the impacts of highway transportation on the environment. These environmental and socioeconomic concerns have to be reflected in our transportation planning and decision making processes. All efforts must be made to ensure that our development policies and programs are consistent with our environmental objectives. This paper discusses the environmental and socioeconomic concerns and how the Environmental Impact Assessment (EIS) can be used as a tool for transportation decision-making as well as for environmental management. ', 'Environmental Impact Assessment (EIS)\nHighway transportation projects ', NULL, NULL, 'Public (Metadata Only)', 'active', '2026-03-18 08:36:49', '2026-03-18 08:36:49'),
